interface TableProps {
  title: string;
  children: React.ReactNode;
}

export default function Table({ title, children }: TableProps) {
  return (
    <table className="w-full lg:w-[80%] flex flex-col gap-4 justify-self-center">
      <th className="border-b border-b-primary pb-2 text-2xl">{title}</th>
      <tbody className="px-2">{children}</tbody>
    </table>
  );
}
